// Parse + repair the local model's plot; any failure routes this item to
// the Claude plot node via the error output. Small models produce JSON with
// `0: "..."` array entries, truncated tails, and trailing commas — repaired here.
const j = $json;
const raw = (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content) || '';
const clean = raw.replace(/```(?:json)?|```/g, '').trim();

function extractJson(text) {
  const startIdx = text.indexOf('{');
  if (startIdx === -1) throw new Error('no JSON object in local plot response');
  // `[0: "x", 1: "y"]` -> `["x", "y"]`
  let s = text.slice(startIdx).replace(/([\[,]\s*)\d+\s*:\s*"/g, '$1"');
  // find the balanced end of the root object, fixing mismatched closers
  // (`]` for `}` and vice versa) along the way; if truncated, close what's open
  let inStr = false, esc = false, end = -1;
  const stack = [];
  const out = s.split('');
  for (let i = 0; i < out.length; i++) {
    const ch = out[i];
    if (esc) { esc = false; continue; }
    if (ch === '\\') { esc = inStr; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (!inStr) {
      if (ch === '{' || ch === '[') stack.push(ch);
      else if (ch === '}' || ch === ']') {
        const open = stack.pop();
        if (open === '[' && ch === '}') out[i] = ']';
        else if (open === '{' && ch === ']') out[i] = '}';
        if (stack.length === 0) { end = i; break; }
      }
    }
  }
  s = out.join('');
  if (end !== -1) {
    s = s.slice(0, end + 1);
  } else {
    if (inStr) s += '"';
    while (stack.length) s += stack.pop() === '{' ? '}' : ']';
  }
  s = s.replace(/,\s*([\]}])/g, '$1');
  return JSON.parse(s);
}

const plot = extractJson(clean);
if (!plot.title) throw new Error('local plot has no title');
let beats = plot.beats;
if (beats && !Array.isArray(beats) && typeof beats === 'object') beats = Object.values(beats);
if (!Array.isArray(beats)) throw new Error('local plot has no beats array');
beats = beats
  .map((b, i) => ({ index: i, beat: typeof b === 'string' ? b : (b && b.beat) || '' }))
  .filter((b) => b.beat.trim().length > 0);
if (beats.length > 12) beats = beats.slice(0, 12);
if (beats.length < 4) throw new Error(`only ${beats.length} usable beats`);
beats = beats.map((b, i) => ({ index: i, beat: b.beat }));
return [{ json: { title: plot.title, tagline: plot.tagline || '', panel_count: beats.length, beats } }];

