const init = $('Init run').first().json;
const idea = $('Extract idea').first().json.idea;
// Input is either a pre-parsed plot (from 'Try local plot') or a raw
// Anthropic response (from 'Plot (Claude)').
let plot;
if (Array.isArray($json.beats)) {
  plot = $json;
} else {
  const raw = ($json.content && $json.content[0] && $json.content[0].text) || '';
  const clean = raw.replace(/```(?:json)?|```/g, '').trim();
  const start = clean.indexOf('{');
  const end = clean.lastIndexOf('}');
  if (start === -1 || end <= start) throw new Error('no JSON object in plot response');
  plot = JSON.parse(clean.slice(start, end + 1));
}
if (!Array.isArray(plot.beats) || plot.beats.length === 0) throw new Error('plot has no beats array');
let n = Number(plot.panel_count);
// Small local models sometimes miscount; trust the beats array when in range.
if (plot.beats.length !== n && plot.beats.length >= 4 && plot.beats.length <= 12) n = plot.beats.length;
if (!(n >= 4 && n <= 12)) throw new Error(`panel_count ${n} outside 4-12`);
if (plot.beats.length !== n) throw new Error(`beats count ${plot.beats.length} != panel_count ${n}`);
if (!plot.title) throw new Error('plot has no title');
return [{ json: { ...init, idea, title: plot.title, tagline: plot.tagline || '', panel_count: n, beats: plot.beats.slice(0, n) } }];

const p = $json;
return p.beats.map((b, i) => ({ json: {
  dir: p.dir,
  index: (b.index === undefined || b.index === null) ? i : b.index,
  beat: b.beat,
  title: p.title,
  tagline: p.tagline,
  panel_count: p.panel_count,
} }));

const src = $('Split beats').item.json;
const suffix = $('Init run').first().json.imageSuffix;
// Accepts both response shapes: local OpenAI-compatible and Anthropic. Any
// parse failure falls back to the raw beat as the image prompt.
const j = $json;
const raw = (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content)
  || (j.content && j.content[0] && j.content[0].text)
  || '';
const clean = raw.replace(/```(?:json)?|```/g, '').trim();
let scene;
try {
  const start = clean.indexOf('{');
  const end = clean.lastIndexOf('}');
  scene = JSON.parse(clean.slice(start, end + 1));
} catch (e) { scene = { image_prompt: src.beat, caption: '', dialogue: '' }; }
const parts = [];
if (scene.caption) parts.push(`Caption bar at the bottom of the panel with the text: "${scene.caption}"`);
if (scene.dialogue) parts.push(`A comic speech bubble in the upper area with the text: "${scene.dialogue}"`);
const prompt = `${scene.image_prompt || src.beat}. ${suffix} ${parts.join(' ')}`.trim();
return { json: { ...src, caption: scene.caption || '', dialogue: scene.dialogue || '', prompt } };

// All scene files are on disk once this runs; collapse to a single item.
const p = $('Parse plot').first().json;
return [{ json: { dir: p.dir, title: p.title, tagline: p.tagline, panel_count: p.panel_count, scenes_written: $input.all().length } }];

const lines = $json.stdout.trim().split('\n');
const result = JSON.parse(lines[lines.length - 1]);
if (!result.size || result.size < 1000) throw new Error(`reel missing or too small: ${JSON.stringify(result)}`);
return [{ json: result }];

const err = $json.error || {};
if (err.code && err.code !== 'ok') throw new Error(`TikTok init failed: ${err.code} — ${err.message} (log_id ${err.log_id})`);
if (!$json.data || !$json.data.upload_url) throw new Error(`TikTok init returned no upload_url: ${JSON.stringify($json)}`);
return [{ json: { upload_url: $json.data.upload_url, publish_id: $json.data.publish_id } }];

return [{ json: {
  message: 'Reel uploaded to TikTok drafts — open the TikTok app (Inbox/Notifications) to caption & post.',
  style: $('Parse plot').first().json.style,
  mode: $('Parse plot').first().json.mode,
  title: $('Parse plot').first().json.title,
  tagline: $('Parse plot').first().json.tagline,
  idea: $('Parse plot').first().json.idea,
  publish_id: $('Parse init').first().json.publish_id,
  reel: $('Parse render').first().json.reel,
} }];
